noncompliant:
char dest[10] = "Hello";
char *src = "World123456";
strncat(dest, src, 20); // Noncompliant: count exceeds destination buffer size

char small[5] = "Hi";
strncat(small, "There", 3); // Noncompliant: insufficient space for null terminator

compliant:
char dest[20] = "Hello";
char *src = "World";
size_t remaining = sizeof(dest) - strlen(dest) - 1;
strncat(dest, src, remaining); // Compliant: proper size calculation

// Or use safer approach:
char result[50];
size_t dest_len = strlen(dest);
if (dest_len < sizeof(result)) {
    strncat(dest, src, sizeof(result) - dest_len - 1); // Compliant
}
